  selectInterfaceMode(value){const next=this.validInterfaceMode(value);const previousEndpoint=this.modelListEndpoint();if(this.interfaceMode===next){this.closeSelect();return}this.interfaceMode=next;this.saveInterfacePreference();this.closeSelect();if(previousEndpoint!==this.modelListEndpoint()){this.model='';this.imageModel='';this.imagePromptOptimizerModel='';this.models=[];this.loadModels()}else{this.ensureTextModelDefaults();this.ensureImageDefaults();this.ensurePromptOptimizerDefaults()}this.saveCurrentChatSession()},
