  cloneChatCfg(value=null){return{...this.defaultChatCfg(),...(value||{})}},
  newChatSessionId(){return`chat-${Date.now()}-${Math.random().toString(16).slice(2)}`},
  sanitizeChatMessage(message){const files=Array.isArray(message?.files)?message.files.map(file=>({name:file.name||'',mime:file.mime||'',size:file.size||0,isImage:!!file.isImage,url:file.url&&!String(file.url).startsWith('data:')?file.url:''})):[];const content=String(message?.content||'');return{role:message?.role==='assistant'?'assistant':'user',content,thinking:String(message?.thinking||''),error:String(message?.error||''),showThinking:!!message?.showThinking,usage:this.normalizeUsage(message?.usage),files,images:files.filter(file=>file.isImage),apiContent:typeof message?.apiContent==='string'?message.apiContent:content}},
  deriveChatSessionTitle(messages=this.msgs){const first=(messages||[]).find(message=>message.role==='user'&&String(message.content||'').trim());const text=String(first?.content||'').trim().replace(/\s+/g,' ');return text?text.slice(0,48):'新对话'},
  normalizeChatSession(session){if(!session||typeof session!=='object')return null;const now=Date.now();const messages=Array.isArray(session.msgs)?session.msgs.map(message=>this.sanitizeChatMessage(message)):[];return{id:String(session.id||this.newChatSessionId()),title:String(session.title||this.deriveChatSessionTitle(messages)),createdAt:Number(session.createdAt||now),updatedAt:Number(session.updatedAt||session.createdAt||now),model:String(session.model||''),chatPreset:String(session.chatPreset||'balanced'),cfg:this.cloneChatCfg(session.cfg),msgs:messages}},
  loadChatSessions(){try{const stored=JSON.parse(localStorage.getItem('aistudio.chatSessions.v1')||'{}');const rawSessions=Array.isArray(stored)?stored:stored.sessions;const sessions=(Array.isArray(rawSessions)?rawSessions:[]).map(session=>this.normalizeChatSession(session)).filter(Boolean).slice(0,this.chatStorageLimit());this.chatSessions=sessions;const activeId=!Array.isArray(stored)&&stored?.activeId?sessions.find(session=>session.id===stored.activeId)?.id:'';if(activeId){this.applyChatSession(sessions.find(session=>session.id===activeId),{persist:false})}else{this.createChatSession({persist:false});this.msgs=[]}this.saveChatSessions()}catch(error){this.chatSessions=[];this.activeChatSessionId='';this.chatSessionError='聊天历史加载失败：浏览器存储不可用';this.createChatSession({persist:false});this.msgs=[]}},
