  createChatSession({persist=true}={}){const now=Date.now();const session={id:this.newChatSessionId(),title:'新对话',createdAt:now,updatedAt:now,model:this.model,chatPreset:this.chatPreset,cfg:this.cloneChatCfg(),msgs:[]};this.chatSessions=[session,...this.chatSessions.filter(item=>item.id!==session.id)].slice(0,this.chatStorageLimit());this.activeChatSessionId=session.id;if(persist)this.saveChatSessions();return session},
  syncActiveChatSession(){if(this.chatRestoring)return null;let session=this.chatSessions.find(item=>item.id===this.activeChatSessionId);if(!session)session=this.createChatSession({persist:false});const updated={...session,title:this.deriveChatSessionTitle(this.msgs),updatedAt:Date.now(),model:this.model,chatPreset:this.chatPreset,cfg:this.cloneChatCfg(),msgs:this.msgs.map(message=>this.sanitizeChatMessage(message))};this.chatSessions=[updated,...this.chatSessions.filter(item=>item.id!==updated.id)].slice(0,this.chatStorageLimit());this.activeChatSessionId=updated.id;return updated},
  saveCurrentChatSession(){if(this.chatRestoring)return;this.syncActiveChatSession();this.saveChatSessions()},
  scheduleChatSessionSave(){if(this.chatRestoring)return;if(this.chatSaveTimer)clearTimeout(this.chatSaveTimer);this.chatSaveTimer=setTimeout(()=>{this.chatSaveTimer=null;this.saveCurrentChatSession()},150)},
  applyChatSession(session,{persist=true}={}){if(!session)return;const normalized=this.normalizeChatSession(session);if(!normalized)return;this.chatRestoring=true;this.activeChatSessionId=normalized.id;if(normalized.model)this.model=normalized.model;this.chatPreset=normalized.chatPreset||'balanced';this.cfg=this.cloneChatCfg(normalized.cfg);this.msgs=normalized.msgs.map(message=>this.sanitizeChatMessage(message));this.draft='';this.chatFiles=[];this.chatFileError='';if(this.models.length)this.ensureTextModelDefaults();else this.applyModelCapabilities();this.chatRestoring=false;if(persist)this.saveChatSessions();this.scrollDown()},
