  newChatSession(){if(this.busy)return;this.saveCurrentChatSession();this.chatRestoring=true;const session=this.createChatSession({persist:false});this.activeChatSessionId=session.id;this.msgs=[];this.draft='';this.chatFiles=[];this.chatFileError='';this.chatRestoring=false;this.saveChatSessions();this.scrollDown();this.showToast('已开启新聊天')},
  deleteChatSession(session){if(!session?.id||this.busy)return;const deletingActive=session.id===this.activeChatSessionId;this.chatSessions=this.chatSessions.filter(item=>item.id!==session.id);if(!this.chatSessions.length){this.chatRestoring=true;const next=this.createChatSession({persist:false});this.activeChatSessionId=next.id;this.msgs=[];this.draft='';this.chatFiles=[];this.chatFileError='';this.chatRestoring=false}else if(deletingActive){this.applyChatSession(this.chatSessions[0],{persist:false})}this.saveChatSessions();this.showToast('已删除聊天')},
  chatSessionMeta(session){const count=(session?.msgs||[]).length;const time=session?.updatedAt?new Date(session.updatedAt).toLocaleString():'-';return`${count} 条 · ${time}`},
  chatSessionPreview(session){const last=(session?.msgs||[]).slice().reverse().find(message=>String(message.content||message.error||'').trim());const text=String(last?.error||last?.content||'').trim().replace(/\s+/g,' ');return text?text.slice(0,72):'暂无消息'},
  get orderedChatSessions(){return[...this.chatSessions].sort((left,right)=>(right.updatedAt||0)-(left.updatedAt||0))},
  get chatSessionCount(){return this.chatSessions.length},
  usageNumber(value){const number=Number(value);return Number.isFinite(number)&&number>0?number:0},
  normalizeUsage(usage){const promptDetails=usage?.prompt_tokens_details||{};const completionDetails=usage?.completion_tokens_details||{};const prompt=this.usageNumber(usage?.prompt_tokens??usage?.input_tokens);const completion=this.usageNumber(usage?.completion_tokens??usage?.output_tokens);const total=this.usageNumber(usage?.total_tokens)||(prompt+completion);const cached=this.usageNumber(usage?.cached_tokens??promptDetails.cached_tokens??promptDetails.cache_read_input_tokens);const reasoning=this.usageNumber(completionDetails.reasoning_tokens);return{prompt_tokens:prompt,completion_tokens:completion,total_tokens:total,cached_tokens:cached,completion_tokens_details:{reasoning_tokens:reasoning},prompt_tokens_details:{cached_tokens:cached}}},
  mergeUsageTotals(total,usage){const normalized=this.normalizeUsage(usage);['prompt_tokens','completion_tokens','total_tokens','cached_tokens'].forEach(key=>{total[key]=(total[key]||0)+normalized[key]});const details=total.completion_tokens_details||{};details.reasoning_tokens=(details.reasoning_tokens||0)+normalized.completion_tokens_details.reasoning_tokens;total.completion_tokens_details=details;return total},
  get chatUsageTotals(){return this.msgs.reduce((total,message)=>this.mergeUsageTotals(total,message.usage),{prompt_tokens:0,completion_tokens:0,total_tokens:0,cached_tokens:0,completion_tokens_details:{reasoning_tokens:0}})},
