  closeMessageMenu(){this.messageMenuIndex=null},
  toggleMessageMenu(index,event){event?.stopPropagation?.();this.messageMenuIndex=this.messageMenuIndex===index?null:index},
  messagePlainText(message){return String(message?.error||message?.content||message?.thinking||'').trim()},
  messageMarkdownText(message){const role=message?.role==='user'?'User':'Assistant';const body=this.messagePlainText(message);return body?`**${role}**\n\n${body}`:''},
  async writeClipboard(text){if(!text){this.showToast('没有可复制内容');return}try{if(navigator.clipboard?.writeText)await navigator.clipboard.writeText(text);else throw new Error('clipboard unavailable')}catch(error){const area=document.createElement('textarea');area.value=text;area.setAttribute('readonly','');area.style.position='fixed';area.style.opacity='0';document.body.appendChild(area);area.select();document.execCommand('copy');area.remove()}this.showToast('已复制')},
  async copyMessage(m){await this.copyMessageText(m)},
