  async copyMessageMarkdown(m){await this.writeClipboard(this.messageMarkdownText(m));this.closeMessageMenu()},
  beginEditMessage(index){const message=this.msgs[index];if(!message||message.role!=='user'||this.busy)return;this.editingMessageIndex=index;this.editingMessageDraft=String(message.content||'');this.closeMessageMenu()},
  cancelEditMessage(){this.editingMessageIndex=null;this.editingMessageDraft=''},
  async saveEditedMessage(index){if(this.busy||this.editingMessageIndex!==index)return;const text=this.editingMessageDraft.trim();if(!text){this.showToast('消息不能为空');return}const message=this.msgs[index];if(!message||message.role!=='user')return;const files=Array.isArray(message.files)?message.files.map(file=>({...file})):[];this.msgs.splice(index,this.msgs.length-index,{...message,content:text,apiContent:this.chatMessageApiContent(text,files),files,images:files.filter(file=>file.isImage)});this.cancelEditMessage();this.saveCurrentChatSession();await this.completeChatFromCurrentMessages()},
  deleteMessage(index){if(this.busy||index<0||index>=this.msgs.length)return;this.msgs.splice(index,1);this.cancelEditMessage();this.closeMessageMenu();this.saveCurrentChatSession();this.showToast('已删除消息')},
  branchFromMessage(index){if(this.busy||index<0||index>=this.msgs.length)return;this.saveCurrentChatSession();const messages=this.msgs.slice(0,index+1).map(message=>this.sanitizeChatMessage(message));const now=Date.now();const session={id:this.newChatSessionId(),title:this.deriveChatSessionTitle(messages),createdAt:now,updatedAt:now,model:this.model,chatPreset:this.chatPreset,cfg:this.cloneChatCfg(),msgs:messages};this.chatSessions=[session,...this.chatSessions.filter(item=>item.id!==session.id)].slice(0,this.chatStorageLimit());this.applyChatSession(session);this.closeMessageMenu();this.showToast('已从此处创建分支')},
  async makeMessageApp(index){if(this.busy||index<0||index>=this.msgs.length)return;const source=this.messagePlainText(this.msgs[index]);if(!source){this.showToast('没有可转换的内容');return}this.saveCurrentChatSession();const baseMessages=this.msgs.slice(0,index+1).map(message=>this.sanitizeChatMessage(message));const prompt=`请把下面这段内容转换成一个可直接运行的单文件 Web App。\n\n要求：\n- 使用 HTML、CSS 和原生 JavaScript。\n- 第一屏就是可用界面，不要写营销落地页。\n- 控件完整、布局紧凑、移动端可用。\n- 直接输出完整代码。\n\n内容：\n${source}`;baseMessages.push({role:'user',content:prompt,apiContent:prompt,files:[],images:[]});const now=Date.now();const session={id:this.newChatSessionId(),title:'Make app · '+this.deriveChatSessionTitle(baseMessages).slice(0,36),createdAt:now,updatedAt:now,model:this.model,chatPreset:this.chatPreset,cfg:this.cloneChatCfg(),msgs:baseMessages};this.chatSessions=[session,...this.chatSessions.filter(item=>item.id!==session.id)].slice(0,this.chatStorageLimit());this.applyChatSession(session);this.closeMessageMenu();this.saveCurrentChatSession();await this.completeChatFromCurrentMessages()},
